getDatabasesSql: SHOW DATABASES
getSchemasSql: 
getTypesSql: UNSUPPORTED: Capability not supported: type on mariadb.
getTablesSql: SELECT TABLE_NAME AS table_name, TABLE_TYPE AS table_type, TABLE_SCHEMA AS table_schema, ENGINE AS engine, TABLE_COMMENT AS table_comment, TABLE_ROWS AS table_rows, TABLE_COLLATION AS table_collation, AUTO_INCREMENT AS auto_increment, DATA_LENGTH AS data_length, INDEX_LENGTH AS index_length, DATA_FREE AS data_free, CREATE_OPTIONS AS create_options, CASE WHEN CREATE_OPTIONS LIKE '%partitioned%' THEN 1 ELSE 0 END AS partitioned FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'app' ORDER BY TABLE_NAME
getColumnsSql: SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'app' AND TABLE_NAME = 'users' ORDER BY ORDINAL_POSITION
getAllColumnsSql: SELECT * FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = 'public' ORDER BY TABLE_NAME, ORDINAL_POSITION
getAllIndexesSql: SELECT * FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA = 'public' ORDER BY TABLE_NAME, INDEX_NAME, SEQ_IN_INDEX
getAllForeignKeysSql: SELECT * FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE TABLE_SCHEMA = 'public' AND REFERENCED_TABLE_NAME IS NOT NULL ORDER BY TABLE_NAME, CONSTRAINT_NAME, ORDINAL_POSITION
getTableStatusSql: SELECT TABLE_NAME AS table_name, TABLE_TYPE AS table_type, TABLE_SCHEMA AS table_schema, ENGINE AS engine, TABLE_COMMENT AS table_comment, TABLE_ROWS AS table_rows, TABLE_COLLATION AS table_collation, AUTO_INCREMENT AS auto_increment, DATA_LENGTH AS data_length, INDEX_LENGTH AS index_length, DATA_FREE AS data_free, CREATE_OPTIONS AS create_options, CASE WHEN CREATE_OPTIONS LIKE '%partitioned%' THEN 1 ELSE 0 END AS partitioned FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = 'app' AND TABLE_NAME = 'users' ORDER BY TABLE_NAME
getViewsSql: SELECT TABLE_NAME AS view_name, TABLE_SCHEMA AS table_schema, VIEW_DEFINITION AS view_definition, 0 AS materialized FROM INFORMATION_SCHEMA.VIEWS WHERE TABLE_SCHEMA = 'public' ORDER BY TABLE_SCHEMA, TABLE_NAME
getViewDefinitionSql: SELECT VIEW_DEFINITION AS definition FROM INFORMATION_SCHEMA.VIEWS WHERE TABLE_SCHEMA = 'app' AND TABLE_NAME = 'users'
getIndexesSql: SHOW INDEX FROM `app`.`public`.`users`
getForeignKeysSql: SELECT * FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE TABLE_SCHEMA = 'app' AND TABLE_NAME = 'users' AND REFERENCED_TABLE_NAME IS NOT NULL
getReferencingForeignKeysSql: SELECT * FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE WHERE REFERENCED_TABLE_SCHEMA = 'app' AND REFERENCED_TABLE_NAME = 'users' AND REFERENCED_COLUMN_NAME IS NOT NULL
getTriggersSql: SHOW TRIGGERS FROM `app`
getRoutinesSql: SELECT * FROM INFORMATION_SCHEMA.ROUTINES WHERE ROUTINE_SCHEMA = 'public'
getCheckConstraintsSql: SELECT CONSTRAINT_NAME AS constraint_name, CHECK_CLAUSE AS check_clause, 0 AS not_enforced FROM INFORMATION_SCHEMA.CHECK_CONSTRAINTS WHERE CONSTRAINT_SCHEMA = 'app' AND TABLE_NAME = 'users'
